export enum UserRole {
  CLUB_REP = 'CLUB_REP',
  ADVISOR = 'ADVISOR',
  MPP_EXCO = 'MPP_EXCO',
  HEPA_STAFF = 'HEPA_STAFF'
}

export enum ProposalStatus {
  PENDING_ADVISOR = 'PENDING_ADVISOR',
  PENDING_MPP = 'PENDING_MPP',
  NEEDS_IMPROVEMENT = 'NEEDS_IMPROVEMENT',
  APPROVED = 'APPROVED',
  REJECTED = 'REJECTED',
  COMPLETED = 'COMPLETED' // Event done, report submitted
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  clubName?: string; // Only for Club Reps
}

export interface Comment {
  id: string;
  authorName: string;
  authorRole: UserRole;
  content: string;
  timestamp: string;
  type: 'general' | 'amendment_request' | 'rejection_reason';
}

export interface Proposal {
  id: string;
  title: string;
  clubName: string;
  submitterName: string;
  dateSubmitted: string;
  eventDate: string;
  venue: string;
  objective: string;
  participants: string;
  description: string;
  status: ProposalStatus;
  documents: { name: string; url: string }[];
  comments: Comment[];
  history: { status: ProposalStatus; timestamp: string; actor: string }[];
  postEventReport?: {
    reportFile: string;
    photos: string[];
    submittedDate: string;
  };
}

import React, { createContext, useContext, useState, ReactNode } from 'react';
import { User, UserRole } from '../types';

interface AuthContextType {
  user: User | null;
  login: (email: string, role: UserRole) => void;
  logout: () => void;
  isAuthenticated: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);

  const login = (email: string, role: UserRole) => {
    // Simulating login with mock data based on role
    const mockUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      name: email.split('@')[0].toUpperCase(),
      email,
      role,
      clubName: role === UserRole.CLUB_REP ? 'Computer Science Club' : undefined,
    };
    setUser(mockUser);
  };

  const logout = () => {
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ user, login, logout, isAuthenticated: !!user }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

import React, { createContext, useContext, useState, ReactNode } from 'react';
