  addComment: (proposalId: string, comment: Omit<Comment, 'id' | 'timestamp'>) => void;
  submitReport: (proposalId: string, reportData: { reportFile: string; photos: string[] }) => void;
  getStats: (role: UserRole, clubName?: string) => any;
}

