             {/* Comments Section */}
             <div className="bg-white rounded-xl shadow-sm border border-slate-100 p-6">
                <h3 className="text-lg font-bold text-slate-800 mb-4">Discussion & Feedback</h3>
                <div className="space-y-6">
                    {proposal.comments.length === 0 ? (
